def generate(seed):
    rng = random.Random(seed)

    # Generate two random primes
    p = rng.choice([3, 5, 7, 11, 13, 17, 19, 23])
    g = rng.choice([2, 3, 5, 7, 11, 13, 17, 19, 23])

    # The k-th root of g modulo p is a number h such that h^k ≡ g (mod p).
    # We compute the k-th root of g modulo p.
    k = rng.choice([2, 3, 4, 5])

    # Add a case analysis branch: consider the sign of the coefficients
    if rng.choice([True, False]):
        problem = (
            f"Compute the {k}-th root of {g} modulo {p}. Also, determine the sign of the coefficients."
        )
    else:
        problem = (
            f"Compute the {k}-th root of {g} modulo {p}."
        )

    # Add a dimension lift: consider the system in a higher dimension
    if rng.choice([True, False]):
        problem = (
            f"Consider the {k}-th root in a higher dimension:\n"
            f"Compute the {k}-th root of {g} modulo {p}. Also, determine the sign of the coefficients."
        )

    # Add a hidden identity: consider the system in terms of a known identity
    if rng.choice([True, False]):
        problem = (
            f"Consider the {k}-th root in terms of a known identity:\n"
            f"Compute the {k}-th root of {g} modulo {p}. Also, determine the sign of the coefficients. Additionally, identify the hidden identity that can be used to solve the system."
        )

    return problem, str(g ** (1/k) % p)

